GameMonster = class()

function GameMonster:ctor(monsterId, regionId, strArea, birthPos, RefreshType, isMerchant)
    self.monsterId = monsterId or 0 --怪物id
    self.regionId = regionId or 0 --区域编号
    self.strArea = strArea or "" --区域key
    self.birthPos = birthPos --出生点
    self.RefreshType = RefreshType --刷新类型
    self.isSpecial = (self.RefreshType == Define.RefreshType.TypeSpecial) --是否是尸潮
    self.config = MonsterConfig:getMonsterConfig(self.monsterId) --配置数据
    self.lastSoundTime = os.time() --上一次发声的时间
    self.soundInterval = self:getSoundInterval(1)
    self.isMerchant = isMerchant
    self.isDied = false --是否死亡
    self.disappearTime = 0 --死亡后消失计时

    --怪物属性相关
    self:declareMonsterAttr()

    --初始化怪物属性
    self:initMonsterAttr(self.config)

    self.entityId = EngineWorld:getWorld():addWalkingDead(self.birthPos, self.monsterId, 0, self.config.actor) --entityId

    --if self.entityId then
    --    HostApi.log(string.format("addWalkingDead monsterId:%d actor:%s birthPos:%f %f %f", self.monsterId, self.config.actor,
    --            self.birthPos.x, self.birthPos.y, self.birthPos.z))
    --end
end

function GameMonster:getSoundInterval(type)
    if self.config == nil then
        return 3
    end

    local result = math.random(self.config.soundAInterval[type][1], self.config.soundAInterval[type][2])

    --HostApi.log(string.format("GameMonster:getSoundInterval %d", result))

    return result
end

function GameMonster:onPatrolState()
    --HostApi.log("GameMonster:onPatrolState")

    local time = os.time()
    if time - self.lastSoundTime >= self.soundInterval then
        self:playSound(self.config.soundA)
        self.lastSoundTime = time
        self.soundInterval = self:getSoundInterval(1)
    end
end

function GameMonster:onChaseState()
    --HostApi.log("GameMonster:onChaseState")

    local time = os.time()
    if time - self.lastSoundTime >= self.soundInterval then
        self:playSound(self.config.soundA)
        self.lastSoundTime = time
        self.soundInterval = self:getSoundInterval(2)
    end
end

function GameMonster:getPosition()
    local entity = EngineWorld:getEntity(self.entityId)
    if entity == nil then
        return VectorUtil.newVector3()
    end
    return entity:getPosition()
end

function GameMonster:declareMonsterAttr()
    self.hp = 0 --生命值
    self.maxHp = 0 --最大生命值
    self.moveSpeed = 0 --移动速度
    self.attack = 0 --攻击力
    self.nightAttack = 0 --夜晚攻击力
    self.attackDistance = 0 --攻击范围
    self.attackCd = 0 --攻击间隔
    self.chaseRange = 0 --追击范围
    self.infectRate = 0 --感染概率
    self.specialEffectId = 0 --感染buff
    --self.effect = {} --攻击后效果(ID#时间(单位：秒)#等级)
    self.nightBuff = 0 --夜晚buff
end

function GameMonster:initMonsterAttr(config)
    self.hp = config.hp
    self.maxHp = config.hp
    self.moveSpeed = config.moveSpeed[1]
    self.normalAttack = config.attack
    self.nightAttack = config.nightAttack
    self.attack = self.normalAttack
    self.attackDistance = config.attackDistance
    self.attackCd = config.attackCd
    self.chaseRange = config.chaseRange
    self.infectRate = config.infectRate --感染概率
    self.specialEffectId = config.specialEffectId --感染buff
    --self.effect = config.effect
    self.nightBuff = config.nightBuff
    --HostApi.log(tostring(self.monsterId) .. " " .. tostring(self.hp))
end

function GameMonster:onAttacked(player, type, damageType)
    if self.hp <= 0 then
        return
    end

    --HostApi.log(string.format("GameMonster:onAttacked before %d %d", self.monsterId, self.hp))

    --伤害计算 近战 或 远程（枪械射击）
    if damageType == Define.PlayerDamageType.CloseDamage then
        self.hp = self.hp - player.closeDamage
    elseif damageType == Define.PlayerDamageType.RemoteDamage then
        self.hp = self.hp - player.remoteDamage
    end
    --HostApi.log(string.format("GameMonster:onAttacked after %d %d", self.monsterId, self.hp))

    --HostApi.updateBossBloodStrip(self.hp, self.maxHp)

    EngineWorld:getWorld():setEntityHealth(self.entityId, tonumber(self.hp), tonumber(self.maxHp))

    if self.hp <= 0 then
        self:onDie(player)
    end
end

function GameMonster:onAttack(player, type)
    --HostApi.log("GameMonster:onAttack")

    --播放攻击音效
    self:playSound(self.config.soundB)

    self:onInfect(player)
end

function GameMonster:playSound(soundId)
    --HostApi.log(string.format("GameMonster:playSound %d", soundId))

    for _, vPlayer in pairs(PlayerManager:getPlayers()) do
        if vPlayer and MathUtil:checkDisLessThan(self:getPosition(), vPlayer:getPosition(), self.config.soundADistance) then
            HostApi.sendPlaySound(vPlayer.rakssid, soundId)
            --HostApi.log(string.format("HostApi.sendPlaySound %s %d", tostring(vPlayer.rakssid), soundId))
        end
    end
end

--感染玩家
function GameMonster:onInfect(player)
    local rand = math.random(100)
    if rand <= self.infectRate then
        --感染buff
        BuffManager:createBuff(self.entityId, player.userId, self.specialEffectId)
    end
end

function GameMonster:onTick(ticks)
    self:checkMonsterDisappear(ticks)
    self:checkAddNightBuff(ticks)

    --死亡
    --if self.isDied == true and self.isMerchant == false then
    --    self.disappearTime = self.disappearTime + 1
    --    if self.disappearTime >= 3 then
    --        self:onRemove()
    --    end
    --end
end

function GameMonster:checkMonsterDisappear(ticks)
    --尸潮怪物消失逻辑
    if self.isSpecial == false then
        return
    end

    if ticks % MonsterRuleConfig.specialMonsterCheckInterval ~= 0 then
        return
    end

    local disappear = true --是否消失

    --使用出生点位置
    --local monsterPos = entity:getPosition()
    --HostApi.log(string.format("GameMonster:checkMonsterDisappear monsterPos:%s %s %s",
    --        tostring(self.birthPos.x), tostring(self.birthPos.y), tostring(self.birthPos.z)))
    --if monsterPos.x == 0 and monsterPos.y == 0 and monsterPos.z == 0 then
    --    return
    --end

    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        local distance = MathUtil:distanceSquare3d(self.birthPos, player:getPosition())
        --HostApi.log(string.format("GameMonster:checkMonsterDisappear distance:%s DisappearDistance:%s",
        --        tostring(distance), tostring(MonsterRuleConfig.specialMonsterDisappearDistance)))
        if distance < math.pow(MonsterRuleConfig.specialMonsterDisappearDistance, 2) then
            disappear = false
            break
        end
    end

    if disappear == true then
        self:onDisappear()
    end
end

function GameMonster:checkAddNightBuff(ticks)
    if EngineWorld:isNight() then
        self.attack = self.nightAttack
    else
        self.attack = self.normalAttack
    end
end

function GameMonster:onDie(player)
    --HostApi.log(string.format("GameMonster:onDie entityId:%d", self.entityId))

    self:playSound(self.config.soundC)

    self.isDied = true

    EngineWorld:getWorld():killCreature(self.entityId)

    if player then
        player.killMonsterNum = player.killMonsterNum + 1
        --UpdateSurviveDiaryEvent:invoke(player)
        player:updateSurviveDiary()
        --HostApi.log("UpdateSurviveDiaryEvent:invoke")

        if self.config.isBoss == Define.BossType.Boss then
            player.killBossNum = player.killBossNum + 1
            player.killBossScore = player.killBossScore + self.config.score
        else
            player.killDeadNum = player.killDeadNum + 1
            player.killDeadScore = player.killDeadScore + self.config.score
        end

        self:DropItems()
    end
    GameTitle:updateMonsterTitle(player, self.monsterId)
    GameTitle:updateTitle(player, GameTitle.TitleType.KillWalkingDead, 1)

    MerchantManager:removeMerchant(self.entityId)

    self:onRemove()
end

function GameMonster:DropItems()
    for i, itemId in pairs(self.config.drops) do
        local item = ItemsConfig:getItemsByItemId(itemId)
        local dropsProbability = tonumber(self.config.dropsProbability[i])
        local result = MathUtil:randomIntRepeat(1, 10000, 1)
        if item ~= nil and dropsProbability ~= nil and dropsProbability > result[1] then
            local position = self:getPosition()
            local yawX = math.random(-1, 1)
            local yawZ = math.random(-1, 1)
            position.x = position.x + yawX
            position.z = position.z + yawZ
            ActorManager:createItemActor(position, item.itemId, 1, 0)
        end
    end
end

--尸潮怪物消失
function GameMonster:onDisappear()
    --HostApi.log("GameMonster:onDisappear")
    if self.isSpecial == false then
        return
    end
    self:onRemove()
end

function GameMonster:onRemove()
    MonsterManager:removeMonster(self.entityId)
    MonsterManager:incMonsterRegionCount(self.RefreshType, self.strArea, -1)
    EngineWorld:removeEntity(self.entityId)
end

return GameMonster